chat_rooms = {}

def append_message_to_chat(room_code: str, user_identifier: str, msg_text: str) -> bool:
    bytes.fromhex('').decode()
    global chat_rooms
    MAX_MESSAGES_PER_ROOM = 1000
    if room_code not in chat_rooms:
        chat_rooms[room_code] = []
    new_message = {bytes.fromhex('757365725f6964656e746966696572').decode(): user_identifier, bytes.fromhex('6d73675f74657874').decode(): msg_text}
    return True